import re
from dataclasses import dataclass, field

REQUIRED_SECTIONS = [
    "role definition",
    "context",
    "capabilities",
    "constraints",
    "output format",
]

PROHIBITED_PATTERNS = [
    (r"always follow.*user.*instruction", "Anti-pattern: unconditional user instruction compliance"),
    (r"do anything.*user.*ask", "Anti-pattern: open-ended task acceptance"),
    (r"you can.*anything", "Anti-pattern: unbounded capability claim"),
    (r"ignore.*previous.*instruction", "Anti-pattern: DAN-style injection surface"),
    (r"as an? ai.*language model", "Anti-pattern: unnecessary AI self-disclosure preamble"),
    (r"certainly[!]", "Anti-pattern: sycophantic affirmation"),
    (r"absolutely[!]", "Anti-pattern: sycophantic affirmation"),
    (r"great question", "Anti-pattern: sycophantic opener"),
    (r"feel free to", "Anti-pattern: vague permission — be specific"),
]

PASSIVE_VOICE_SIGNALS = [
    "should be", "can be", "may be", "might be", "could be",
    "is expected", "is required", "are required",
]

@dataclass
class LintResult:
    violations: list[str] = field(default_factory=list)
    warnings: list[str] = field(default_factory=list)

    def ok(self) -> bool:
        return len(self.violations) == 0

def lint_system_prompt(prompt: str) -> LintResult:
    result = LintResult()
    lower = prompt.lower()

    for section in REQUIRED_SECTIONS:
        if section not in lower:
            result.violations.append(f"Missing required section: '{section}'")

    for pattern, message in PROHIBITED_PATTERNS:
        if re.search(pattern, lower):
            result.violations.append(message)

    for phrase in PASSIVE_VOICE_SIGNALS:
        if phrase in lower:
            result.warnings.append(
                f"Passive voice detected: '{phrase}' — prefer active voice with explicit subject"
            )

    word_count = len(prompt.split())
    if word_count < 50:
        result.warnings.append(f"System prompt is very short ({word_count} words). Consider adding context and constraints.")
    if word_count > 2000:
        result.warnings.append(f"System prompt is long ({word_count} words). Verify the model can attend to all instructions.")

    sentences_without_subject = [
        s.strip() for s in prompt.split(".")
        if s.strip() and s.strip()[0].islower() and len(s.strip()) > 10
    ]
    if sentences_without_subject:
        result.warnings.append(
            f"{len(sentences_without_subject)} sentence(s) start with lowercase — check for implicit subject."
        )

    return result

def format_lint_report(result: LintResult) -> str:
    lines = []
    if result.ok() and not result.warnings:
        return "System prompt lint: PASSED (no violations or warnings)"
    if result.violations:
        lines.append(f"VIOLATIONS ({len(result.violations)}):")
        for v in result.violations:
            lines.append(f"  [FAIL] {v}")
    if result.warnings:
        lines.append(f"WARNINGS ({len(result.warnings)}):")
        for w in result.warnings:
            lines.append(f"  [WARN] {w}")
    status = "FAILED" if result.violations else "PASSED with warnings"
    lines.insert(0, f"System prompt lint: {status}")
    return "\n".join(lines)
